INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (100, 2.1, 130011, 2, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 3001, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "ヤマト", 3001100, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (101, 5.68, 130011, 2, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 3001, 4, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "ヤマト", 3001101, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (102, 0.0, 130011, 1, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 3001, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "ヤマト", 3001102, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (100, 0.0, 130211, 1, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 3002, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "フブキ", 3002100, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (101, 0.0, 130211, 1, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 3002, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "フブキ", 3002101, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (102, 8.53, 130211, 2, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 3002, 5, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "フブキ", 3002102, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (103, 5.67, 130211, 1, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 3002, 7, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "フブキ", 3002103, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (104, 0.0, 130211, 1, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 3002, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "フブキ", 3002104, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (300, 0.0, 130211, 3, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 3004, 3, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "フブキ", 3002300, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (301, 0.0, 130211, 7, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 3005, 7, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "フブキ", 3002400, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (200, 4.4, 130211, 1, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 3003, 2, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "フブキ", 3003200, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (201, 0.0, 130211, 7, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 3003, 7, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "フブキ", 3003201, -416.5, 0.0);
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES (202, 5.6, 130211, 2, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 3003, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", "フブキ", 3003202, -416.5, 0.0);
